"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[50795],{43923:i=>{i.exports=JSON.parse('{"tag":{"label":"illnesses","permalink":"/docs/tags/illnesses","allTagsPath":"/docs/tags","count":35,"items":[{"id":"guinea-pigs/illnesses-and-conditions/bordetella-in-guinea-pigs","title":"Bordetella in Guinea Pigs","description":"Bordetella bronchiseptica is a bacterium that causes respiratory disease in a variety of animals. While it is most commonly known as a cause of \'kennel cough\' in dogs, it can be a life-threatening...","permalink":"/docs/guinea-pigs/illnesses-and-conditions/bordetella-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/bumblefoot-in-guinea-pigs","title":"Bumblefoot in Guinea Pigs","description":"Learn about bumblefoot (pododermatitis) in guinea pigs \u2014 causes, warning signs, treatment, and how to prevent this painful foot condition with proper housing.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/bumblefoot-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/cl","title":"Caseous/Cervical Lymphadenitis in Guinea Pigs","description":"Guinea pigs are beloved pets known for their friendly and gentle nature, but like all animals, they can be susceptible to a variety of health issues. One condition that can affect them is Caseous Lymphadenitis (CL), a bacterial infection that causes swelling and abscesses in the lymph nodes. This disease can be serious and requires prompt treatment to avoid complications.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/cl"},{"id":"guinea-pigs/illnesses-and-conditions/coccidia-in-guinea-pigs","title":"Coccidia in Guinea Pigs","description":"Understand coccidia in guinea pigs \u2014 what it is, how it spreads, symptoms to watch for, how it\'s diagnosed and treated, and how to prevent it.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/coccidia-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/coccidia-in-rabbits","title":"Coccidia in Rabbits","description":"A comprehensive guide to coccidiosis in rabbits \u2014 causes, symptoms, diagnosis, treatment, and prevention of this common parasitic infection.","permalink":"/docs/Rabbits/illnesses-and-conditions/coccidia-in-rabbits"},{"id":"Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas","title":"Dental Disease in Chinchillas","description":"Learn about the causes, symptoms, and treatment of dental disease and malocclusion in chinchillas, including how diet and genetics play a role.","permalink":"/docs/Chinchillas/illnesses-and-conditions/dental-disease-in-chinchillas"},{"id":"Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas","title":"Diabetes in Chinchillas","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in chinchillas, including diet and lifestyle changes.","permalink":"/docs/Chinchillas/illnesses-and-conditions/diabetes-in-chinchillas"},{"id":"Degus/illnesses-and-conditions/diabetes-in-degus","title":"Diabetes in Degus","description":"Learn about the causes, symptoms, diagnosis, and management of diabetes mellitus in degus \u2014 one of the most diabetes-prone small mammals kept as pets.","permalink":"/docs/Degus/illnesses-and-conditions/diabetes-in-degus"},{"id":"guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs","title":"Diabetes in Guinea Pigs","description":"Learn about diabetes mellitus in guinea pigs \u2014 causes, symptoms, diagnosis, management, and how diet and lifestyle changes can help your guinea pig live well.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs"},{"id":"Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs","title":"Diabetes in Hedgehogs","description":"A comprehensive guide to diabetes in hedgehogs \u2014 causes, signs, diagnosis, and management strategies for this common metabolic condition.","permalink":"/docs/Hedgehogs/illnesses-and-conditions/diabetes-in-hedgehogs"},{"id":"Hamsters/illnesses-and-conditions/diabetes-in-hamsters","title":"Diabetes in Pet Hamsters","description":"A comprehensive guide to diabetes in hamsters \u2014 which breeds are most at risk, signs and symptoms, diagnosis, and management strategies.","permalink":"/docs/Hamsters/illnesses-and-conditions/diabetes-in-hamsters"},{"id":"Mice/illnesses-and-conditions/diabetes-in-mice","title":"Diabetes in Pet Mice","description":"A guide to diabetes in pet mice \u2014 causes, symptoms, diagnosis, and management strategies for this metabolic condition.","permalink":"/docs/Mice/illnesses-and-conditions/diabetes-in-mice"},{"id":"Rabbits/illnesses-and-conditions/diabetes-in-rabbits","title":"Diabetes in Pet Rabbits","description":"A comprehensive guide to diabetes in rabbits \u2014 causes, symptoms, diagnosis, and management of this rare but serious metabolic condition.","permalink":"/docs/Rabbits/illnesses-and-conditions/diabetes-in-rabbits"},{"id":"guinea-pigs/illnesses-and-conditions/e-cuniculi-in-guinea-pigs","title":"E. cuniculi in Guinea Pigs","description":"Learn about Encephalitozoon cuniculi (E. cuniculi) in guinea pigs \u2014 what it is, how it spreads, symptoms including head tilt and seizures, diagnosis, treatment, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/e-cuniculi-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/e-cuniculi-in-rabbits","title":"E. cuniculi in Rabbits","description":"A comprehensive guide to Encephalitozoon cuniculi in rabbits \u2014 transmission, signs, diagnosis, treatment, and prevention of this common neurological parasite.","permalink":"/docs/Rabbits/illnesses-and-conditions/e-cuniculi-in-rabbits"},{"id":"guinea-pigs/illnesses-and-conditions/ear-infections-in-guinea-pigs","title":"Ear Infections in Guinea Pigs","description":"Learn about ear infections in guinea pigs \u2014 causes, warning signs including head tilt and loss of balance, diagnosis, treatment, and how to prevent them.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/ear-infections-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/ear-infections-in-rabbits","title":"Ear Infections in Rabbits","description":"A guide to ear infections in rabbits \u2014 types, causes, symptoms, diagnosis, treatment, and prevention of otitis in pet rabbits.","permalink":"/docs/Rabbits/illnesses-and-conditions/ear-infections-in-rabbits"},{"id":"Rabbits/getting-started/essential-supplies-for-rabbits","title":"Essential Supplies for Your Rabbit Companion","description":"Bringing a rabbit into your home is a long-term commitment, and providing the right supplies is the first step to ensuring a happy, healthy life for your new friend. Rabbits have specific needs that...","permalink":"/docs/Rabbits/getting-started/essential-supplies-for-rabbits"},{"id":"guinea-pigs/illnesses-and-conditions/giardia-in-guinea-pigs","title":"Giardia in Guinea Pigs","description":"Learn about Giardia in guinea pigs \u2014 what it is, how it spreads, symptoms, diagnosis, treatment, and how to prevent this intestinal parasite.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/giardia-in-guinea-pigs"},{"id":"Chinchillas/illnesses-and-conditions/heartdisease","title":"Heart Disease and Heart Failure in Chinchillas","description":"Heart disease and heart failure are relatively uncommon in chinchillas but can still occur, especially as they age or due to certain genetic predispositions. These conditions can be challenging to detect early on, as chinchillas tend to hide their symptoms until the disease has progressed. Understanding the causes, signs, and treatments of heart disease in chinchillas is key to ensuring your pet remains healthy and receives proper care.","permalink":"/docs/Chinchillas/illnesses-and-conditions/heartdisease"},{"id":"Chinchillas/illnesses-and-conditions/heat-stroke-in-chinchillas","title":"Heat Stroke in Chinchillas","description":"Learn how to recognize, prevent, and respond to heat stroke in chinchillas, including emergency first aid and safe temperature ranges.","permalink":"/docs/Chinchillas/illnesses-and-conditions/heat-stroke-in-chinchillas"},{"id":"guinea-pigs/illnesses-and-conditions/lice-in-guinea-pigs","title":"Lice in Guinea Pigs","description":"Learn about lice in guinea pigs \u2014 the species involved, how to identify them, symptoms, treatment options, and how to prevent infestation.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/lice-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/lymphoma","title":"Lymphoma","description":"Lymphoma is a type of cancer that affects the lymphatic system, and while it may be rare in guinea pigs, it\u2019s a serious health condition that pet owners should be aware of. Early detection of lymphoma can significantly improve the chances of managing the disease and providing your guinea pig with a better quality of life. Understanding the nature of lymphoma, recognizing the early signs, and seeking timely veterinary care are crucial steps in ensuring the best possible outcome for your guinea pig.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/lymphoma"},{"id":"guinea-pigs/illnesses-and-conditions/mites-in-guinea-pigs","title":"Mites in Guinea Pigs","description":"Understand mites in guinea pigs \u2014 the different species, symptoms including intense itching and seizures, diagnosis, treatment with ivermectin, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/mites-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/neurologic-diseases-in-guinea-pigs","title":"Neurologic Diseases in Guinea Pigs","description":"An overview of neurologic diseases in guinea pigs \u2014 including E. cuniculi, inner ear infections, stroke, and Vitamin C deficiency \u2014 with symptoms, diagnosis, and treatment.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/neurologic-diseases-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/neurologic-issues-in-rabbits","title":"Neurologic Issues in Rabbits","description":"A guide to neurological conditions in rabbits \u2014 causes, symptoms, diagnosis, treatment, and care for rabbits with neurologic disease.","permalink":"/docs/Rabbits/illnesses-and-conditions/neurologic-issues-in-rabbits"},{"id":"guinea-pigs/illnesses-and-conditions/ovariancysts","title":"Ovarian Cysts","description":"Ovarian cysts are a common health issue in female guinea pigs, especially as they age. These fluid-filled sacs form on the ovaries and can lead to discomfort and health complications if untreated. Here\u2019s everything you need to know about detecting, treating, and preventing ovarian cysts in guinea pigs, as well as why the flank approach is often preferred for surgical removal.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/ovariancysts"},{"id":"Chinchillas/illnesses-and-conditions/parasites-in-chinchillas","title":"Parasites in Chinchillas","description":"Learn about external and internal parasites that can affect chinchillas, including mites, fleas, giardia, and how to prevent and treat infestations.","permalink":"/docs/Chinchillas/illnesses-and-conditions/parasites-in-chinchillas"},{"id":"guinea-pigs/illnesses-and-conditions/parasites-in-guinea-pigs","title":"Parasites in Guinea Pigs","description":"A comprehensive guide to internal and external parasites in guinea pigs, including identification, treatment, and prevention strategies.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/parasites-in-guinea-pigs"},{"id":"Rabbits/illnesses-and-conditions/parasites-in-rabbits","title":"Parasites in Rabbits","description":"A comprehensive overview of common internal and external parasites in rabbits, including mites, fleas, ticks, worms, and protozoa like E. cuniculi and coccidia.","permalink":"/docs/Rabbits/illnesses-and-conditions/parasites-in-rabbits"},{"id":"Chinchillas/illnesses-and-conditions/respiratory-infections-in-chinchillas","title":"Respiratory Infections in Chinchillas","description":"Learn about the causes, symptoms, treatment, and prevention of respiratory infections in chinchillas, including bacterial pneumonia and environmental risk factors.","permalink":"/docs/Chinchillas/illnesses-and-conditions/respiratory-infections-in-chinchillas"},{"id":"guinea-pigs/illnesses-and-conditions/satinsyndrome","title":"Satin Syndrome in Guinea Pigs","description":"\u2705 Download our checklist here and bring it to your vet! \u2705","permalink":"/docs/guinea-pigs/illnesses-and-conditions/satinsyndrome"},{"id":"guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs","title":"Scurvy (Vitamin C Deficiency) in Guinea Pigs","description":"Everything you need to know about scurvy in guinea pigs \u2014 causes, symptoms, treatment, and how to ensure your guinea pig gets enough Vitamin C.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/stroke-in-guinea-pigs","title":"Stroke in Guinea Pigs","description":"Understanding strokes in guinea pigs \u2014 causes, symptoms, emergency response, treatment, and recovery.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/stroke-in-guinea-pigs"},{"id":"guinea-pigs/illnesses-and-conditions/worms-in-guinea-pigs","title":"Worms in Guinea Pigs","description":"A guide to intestinal worm infestations in guinea pigs \u2014 types, symptoms, diagnosis, treatment, and prevention.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/worms-in-guinea-pigs"}],"unlisted":false}}')}}]);